import { toRaw } from 'vue';
/**
 * 递归展开 Zod wrapper（prefault、default、optional 等），获取内侧 schema。
 * Zod 4 中 .prefault({}) 会包裹 ZodRecord，wrapper 的 def 上没有 valueType/keyType，
 * 必须穿透到内层才能正确识别 record 类型。
 */
function unwrapSchema(schema) {
    let current = schema;
    while (current) {
        const def = current?._zod?.def ?? current?.def;
        // 如果 def 不存在或者已经是 record/object/array 等具象类型，停止
        if (!def)
            break;
        if (def.type && def.type !== 'default' && def.type !== 'prefault')
            break;
        // 穿透 wrapper：prefault / default
        const inner = def.innerType;
        if (!inner || inner === current)
            break;
        current = inner;
    }
    return current;
}
/**
 * 判断一个 Zod schema 是否为 record 类型。
 * Zod 4 的 record schema 有 def.valueType 和 def.keyType 属性。
 */
function isRecordSchema(schema) {
    const inner = unwrapSchema(schema);
    const def = inner?._zod?.def ?? inner?.def;
    return def?.type === 'record' || (def?.valueType != null && def?.keyType != null);
}
/** 获取 record schema 的 value schema */
function getRecordValueSchema(schema) {
    const inner = unwrapSchema(schema);
    const def = inner?._zod?.def ?? inner?.def;
    return def?.valueType;
}
/**
 * 对 z.object 的每个顶层字段尝试 safeParse；
 * 成功的字段使用解析结果，失败的回退到上一个有效值。
 * 对于 z.record 字段，逐条验证每个 value，跳过无效条目而不是让整个 record 失败。
 * 这样即使 AI 写入了部分无效数据（如类型不匹配），也不会导致整个 UI 冻结。
 * 新增的角色条目即使只有部分字段有效，也能被正确显示。
 */
function robustParse(schema, raw, prevData) {
    // 先尝试整体解析
    const fullResult = schema.safeParse(raw);
    if (fullResult.success) {
        return { data: fullResult.data, hadErrors: false };
    }
    // 整体解析失败，逐字段容错解析
    const shape = schema.def?.shape ?? schema._zod?.def?.shape;
    if (!shape) {
        // 没有 shape 信息，无法逐字段解析，回退到旧数据
        console.warn('[mvu] robustParse: no shape info, falling back to prev data');
        return { data: prevData, hadErrors: true };
    }
    const result = {};
    let hadErrors = false;
    for (const [key, fieldSchema] of _.entries(shape)) {
        const rawVal = raw[key];
        if (isRecordSchema(fieldSchema) && rawVal != null && typeof rawVal === 'object') {
            // 对 record 类型，逐条验证每个 value
            const valueSchema = getRecordValueSchema(fieldSchema);
            const validEntries = {};
            for (const [entryKey, entryVal] of _.entries(rawVal)) {
                // 先尝试直接解析
                const entryResult = valueSchema?.safeParse?.(entryVal);
                if (entryResult?.success) {
                    validEntries[entryKey] = entryResult.data;
                }
                else {
                    // 直接解析失败，尝试用默认值合并后再解析
                    const defaultResult = valueSchema?.safeParse?.({});
                    if (defaultResult?.success) {
                        // 合并默认值与 AI 写入的部分数据，再解析一次
                        const mergedVal = _.merge({}, defaultResult.data, entryVal);
                        const mergedResult = valueSchema.safeParse(mergedVal);
                        if (mergedResult?.success) {
                            validEntries[entryKey] = mergedResult.data;
                        }
                        else {
                            // 合并也不行，用默认值代替，至少保证渲染不中断
                            validEntries[entryKey] = defaultResult.data;
                            hadErrors = true;
                        }
                    }
                    else {
                        // 连默认值都生成不了，跳过这条
                        hadErrors = true;
                    }
                }
            }
            // 尝试用 fieldSchema 整体验证 validEntries
            const recordResult = fieldSchema.safeParse(validEntries);
            if (recordResult.success) {
                result[key] = recordResult.data;
            }
            else {
                // record 整体验证失败，使用已经逐条验证过的 validEntries
                result[key] = validEntries;
                hadErrors = true;
            }
        }
        else {
            // 非 record 类型，直接 safeParse
            const fieldResult = fieldSchema.safeParse(rawVal);
            if (fieldResult.success) {
                result[key] = fieldResult.data;
            }
            else {
                // 回退到上一个有效值
                result[key] = prevData[key];
                hadErrors = true;
            }
        }
    }
    return { data: result, hadErrors };
}
export function defineMvuDataStore(schema, variable_option, additional_setup) {
    if (variable_option.type === 'message' &&
        (variable_option.message_id === undefined || variable_option.message_id === 'latest')) {
        variable_option.message_id = -1;
    }
    return defineStore(`mvu_data.${_(variable_option)
        .entries()
        .sortBy(entry => entry[0])
        .map(entry => entry[1])
        .join('.')}`, errorCatched(() => {
        const data = ref(schema.parse(_.get(Mvu.getMvuData(variable_option), 'stat_data', {}), { reportInput: true }));
        if (additional_setup) {
            additional_setup(data);
        }
        useIntervalFn(() => {
            const stat_data = _.get(Mvu.getMvuData(variable_option), 'stat_data', {});
            const result = schema.safeParse(stat_data);
            if (result.error) {
                // 整体解析失败，使用容错解析：逐字段/逐条目解析，跳过无效数据
                const { data: fallbackData, hadErrors } = robustParse(schema, stat_data, data.value);
                if (!_.isEqual(data.value, fallbackData)) {
                    ignoreUpdates(() => {
                        data.value = fallbackData;
                    });
                }
                if (hadErrors) {
                    console.warn('[mvu] safeParse failed, used robust fallback:', result.error);
                }
                return;
            }
            if (!_.isEqual(data.value, result.data)) {
                ignoreUpdates(() => {
                    data.value = result.data;
                });
                if (!_.isEqual(stat_data, result.data)) {
                    updateVariablesWith(variables => _.set(variables, 'stat_data', result.data), variable_option);
                }
            }
        }, 2000);
        const { ignoreUpdates } = watchIgnorable(data, new_data => {
            // 深拷贝 Vue Proxy 为普通对象，避免 Zod 解析 Vue Proxy 导致的问题
            const raw = toRaw(new_data);
            const result = schema.safeParse(raw);
            if (result.error) {
                // 容错解析
                const { data: fallbackData } = robustParse(schema, raw, data.value);
                if (!_.isEqual(raw, fallbackData)) {
                    ignoreUpdates(() => {
                        data.value = fallbackData;
                    });
                }
                console.warn('[mvu] safeParse failed during watch, used robust fallback:', result.error);
                return;
            }
            if (!_.isEqual(raw, result.data)) {
                ignoreUpdates(() => {
                    data.value = result.data;
                });
            }
            updateVariablesWith(variables => _.set(variables, 'stat_data', result.data), variable_option);
        }, { deep: true });
        return { data };
    }));
}
